// components/SubmitButton.tsx

import React, {isValidElement} from 'react';
import {Button, Flex} from '../../../../Components';
import {GridItem} from "../../../Molecules";
import type {UseFormReturn} from "react-hook-form";
import type {IButtonProps} from "@lmb/kitsconcerto-types"; // Assuming this path
import type { CustomSubmitButtonProps } from "@lmb/kitsconcerto-types";

interface SubmitButtonProps {
    isSubmitting: boolean;
    handleSubmit: () => void;
    submitButtonProps?:CustomSubmitButtonProps;
    formMethods:UseFormReturn<any>

    // You can add a prop for custom button text or props
}

export const SubmitButton = ({
                                 isSubmitting,
                                 handleSubmit,
                                 submitButtonProps,
                                 formMethods
                             }: SubmitButtonProps) => {

    // Default props
    let buttonProps: Omit<IButtonProps<any>, "onClick"> = {
        label: "Submit",
        isLoadingText: "Please Wait...",
    };

    // 1. Case: "none" → render nothing (but wrapper still returned? You said any condition inside GridItem)
    if (submitButtonProps === "none") {
        return (
            <Flex w="full" alignItems={'flex-end'} flexDirection={'row'} justifyContent={'flex-end'}>
                {/* Empty intentionally */}
            </Flex>
        );
    }

    // 2. Case: submitButtonProps is a function → render its output
    if (typeof submitButtonProps === "function") {
        return (
            <Flex w="full" alignItems={'flex-end'} flexDirection={'row'} justifyContent={'flex-end'}>
                {submitButtonProps(handleSubmit, isSubmitting, formMethods)}
            </Flex>
        );
    }

    // 3. Case: React element → render directly
    if (isValidElement(submitButtonProps)) {
        return (
            <Flex w="full" alignItems={'flex-end'} flexDirection={'row'} justifyContent={'flex-end'}>
                {submitButtonProps}
            </Flex>
        );
    }

    // 4. Case: custom props object → merge overrides
    if (typeof submitButtonProps === "object") {
        buttonProps = submitButtonProps as typeof buttonProps;
    }

    // 5. Default button
    return (
        <Flex w="full" alignItems={'flex-end'} flexDirection={'row'} justifyContent={'flex-end'}>
            <Button
                type="button"
                outlined
                className="default-submit-button"
                style={{
                    borderRadius: "md",
                    fontWeight: "light",
                    w: ["full", "full", "full", "5rem", "7rem"],
                }}
                size="sm"
                label="Submit"
                onClick={handleSubmit}
                loading={isSubmitting}
                disabled={isSubmitting}
                {...buttonProps}
            />
        </Flex>
    );
};
